#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int val;
    struct Node* next;
    struct Node* prev;
} Node;

Node* reverseDLL(Node* head) {
    Node* curr = head;
    Node* newHead = NULL;
    while (curr) {
        Node* nxt = curr->next;
        // swap pointers
        curr->next = curr->prev;
        curr->prev = nxt;
        newHead = curr; // last processed node becomes new head
        curr = nxt;
    }
    return newHead;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        Node *head = NULL, *tail = NULL;
        for (int i = 0; i < N; ++i) {
            int v; scanf("%d", &v);
            Node* nd = (Node*)malloc(sizeof(Node));
            nd->val = v; nd->next = NULL; nd->prev = NULL;
            if (!head) head = tail = nd; else { tail->next = nd; nd->prev = tail; tail = nd; }
        }
        head = reverseDLL(head);
        for (Node* cur = head; cur; cur = cur->next) {
            printf("%d ", cur->val);
        }
        printf("\n");
        // free memory (optional for contest)
        while (head) { Node* tmp = head; head = head->next; free(tmp); }
    }
    return 0;
}

