#include <bits/stdc++.h>
using namespace std;
struct Node {
    int val;
    Node* next;
    Node* prev;
    Node(int v): val(v), next(nullptr), prev(nullptr) {}
};

Node* reverseDLL(Node* head) {
    Node* cur = head;
    Node* newHead = nullptr;
    while (cur) {
        Node* nxt = cur->next;
        swap(cur->next, cur->prev);
        newHead = cur;
        cur = nxt;
    }
    return newHead;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        int N; cin>>N;
        Node *head=nullptr, *tail=nullptr;
        for (int i=0;i<N;++i){
            int v; cin>>v;
            Node* nd = new Node(v);
            if(!head) head=tail=nd; else { tail->next=nd; nd->prev=tail; tail=nd; }
        }
        head = reverseDLL(head);
        for (Node* cur=head; cur; cur=cur->next) cout<<cur->val<<' ';
        cout<<'\n';
        // optional cleanup
        while(head){ Node* tmp=head; head=head->next; delete tmp; }
    }
    return 0;
}

