const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let output = [];
class Node {
    constructor(val) {
        this.val = val;
        this.next = null;
        this.prev = null;
    }
}
function reverseDLL(head) {
    let cur = head;
    let newHead = null;
    while (cur !== null) {
        const nxt = cur.next;
        const tmp = cur.next;
        cur.next = cur.prev;
        cur.prev = tmp;
        newHead = cur;
        cur = nxt;
    }
    return newHead;
}
for (let t = 0; t < T; ++t) {
    const N = Number(input[idx++]);
    let head = null, tail = null;
    for (let i = 0; i < N; ++i) {
        const v = Number(input[idx++]);
        const nd = new Node(v);
        if (head === null) head = tail = nd;
        else { tail.next = nd; nd.prev = tail; tail = nd; }
    }
    head = reverseDLL(head);
    let line = '';
    while (head !== null) {
        line += head.val + ' ';
        head = head.next;
    }
    output.push(line.trimEnd());
